// ==========================================
// 📘 call() IN JAVASCRIPT
// ==========================================

// call() is used to explicitly set value of 'this'


// ==========================================
// 📘 Parent Function
// ==========================================

function SetUsername(username){
    // Imagine complex DB calls here
    this.username = username
    console.log("called");
}


// ==========================================
// 📘 Child Function
// ==========================================

function createUser(username, email, password){
    // Important: Using call() to set 'this'
    SetUsername.call(this, username)

    this.email = email
    this.password = password
}


// ==========================================
// 📘 Object Creation
// ==========================================

const chai = new createUser(
    "chai",
    "chai@fb.com",
    "123"
)

console.log(chai);


// Output:
// called
// createUser { username: 'chai', email: 'chai@fb.com', password: '123' }


// ==========================================
// 📘 Why call(this) is Important?
// ==========================================

// Without call(this):
// 'this' inside SetUsername would refer to global object
// So username would not be set properly on the new object
